    const acctRow = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];
    const reqRow = (await client.query("SELECT * FROM workflow_requests LIMIT 1")).rows[0];

    const world = {
      account: { accountId: acctRow.account_id, name: acctRow.name, tier: acctRow.tier, region: acctRow.region },
      invoices: JSON.parse(reqRow.invoices_json || "[]"),
      shipments: JSON.parse(reqRow.shipments_json || "[]"),
      regulatoryFlags: JSON.parse(reqRow.regulatory_json || "[]"),
      supportCases: JSON.parse(reqRow.support_json || "[]"),
      usage: { priorPeriodUnits: Number(reqRow.prior_period_units), currentPeriodUnits: Number(reqRow.current_period_units) }
    };

